using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) Get strongly-typed JsonTypeInfo<T> directly (no cast needed)
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");

var json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2) Probe without throwing — TryGetTypeInfo returns false if unavailable
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info))
{
    Console.WriteLine($"TryGetTypeInfo(Person) succeeded: {info!.Type.Name}");
}

// For a type with no resolver that covers it, TryGetTypeInfo returns false
var limited = new JsonSerializerOptions();
limited.TypeInfoResolver = new DefaultJsonTypeInfoResolver();
// Remove the resolver so nothing can provide metadata for the type
limited.TypeInfoResolver = JsonTypeInfoResolver.Combine(); // empty composite

if (!limited.TryGetTypeInfo(typeof(Person), out _))
{
    Console.WriteLine("TryGetTypeInfo(Person) on empty resolver: not available (no exception!)");
}

record Person(string Name, int Age);

